 * No external dependencies, no use of `any`, and fully generic.
 */
type Node<T> = (Node<T> | T)[];

export class PersistentVector<T> {
  // ---- constants -----------------------------------------------------------
  private static readonly B = 32;               // branching factor
  private static readonly BIT_SHIFT = 5;        // log2(B)
  private static readonly MASK = PersistentVector.B - 1;

  // ---- fields --------------------------------------------------------------
  private readonly _size: number;   // total number of elements
  private readonly _shift: number;  // how many bits to shift for the root level
  private readonly _root: Node<T>;  // tree of all but the last B elements
  private readonly _tail: T[];      // last up‑to‑B elements (fast path for push)

  // ---- construction ---------------------------------------------------------
  private constructor(size: number, shift: number, root: Node<T>, tail: T[]) {
    this._size = size;
    this._shift = shift;
    this._root = root;
    this._tail = tail;
  }

  /** Create an empty vector. */
  static empty<T>(): PersistentVector<T> {
    // An empty vector starts with shift = BIT_SHIFT, an empty root and tail.
    return new PersistentVector<T>(0, PersistentVector.BIT_SHIFT, [], []);
  }

  // ---- public API -----------------------------------------------------------
  /** Number of elements stored in the vector. */
  get size(): number {
    return this._size;
  }

  /**
   * Retrieve the element at `index`.
   *
   * @throws RangeError if index is negative or not less than `size`.
   */
  get(index: number): T {
    if (index < 0 || index >= this._size) {
      throw new RangeError('Index out of bounds');
    }

    // If the element lives in the tail, fetch it directly.
    if (index >= this.tailOffset()) {
      return this._tail[index & PersistentVector.MASK];
    }

    // Walk the tree from root to leaf.
    let node: Node<T> = this._root;
    for (let level = this._shift; level > 0; level -= PersistentVector.BIT_SHIFT) {
      const idx = (index >>> level) & PersistentVector.MASK;
      node = node[idx] as Node<T>;
    }
    return node[index & PersistentVector.MASK] as T;
  }

  /**
   * Return a new vector with `value` appended.
   *
   * The original vector is left untouched.  This operation runs in O(log₍32₎ n)
   * time and allocates only the nodes on the path to the new leaf.
   */
  push(value: T): PersistentVector<T> {
    const tailLen = this._size - this.tailOffset();

    // Fast path: the current tail still has room.
    if (tailLen < PersistentVector.B) {
      const newTail = this._tail.slice();
      newTail.push(value);
      return new PersistentVector(this._size + 1, this._shift, this._root, newTail);
