/** Parse a URL query string literal into an object type.
 *
 *  Examples:
 *    ParseQuery<"a=1">                // => { a: "1" }
 *    ParseQuery<"a=1&b=2">            // => { a: "1"; b: "2" }
 *    ParseQuery<"x=hi&y=lo&z=1">      // => { x: "hi"; y: "lo"; z: "1" }
 *    ParseQuery<"">                    // => {}
 */
export type ParseQuery<S extends string> =
  S extends ''
    ? {}                                                   // empty query → empty object
    : S extends `${infer Pair}&${infer Rest}`               // split at first '&'
      ? Merge<ParsePair<Pair>, ParseQuery<Rest>>           // recurse on the rest
      : ParsePair<S>;                                      // last (or only) pair

/** Turn a single `key=value` fragment into an object `{ key: value }`. */
type ParsePair<P extends string> =
  P extends `${infer K}=${infer V}` ? { [k in K]: V } : {}; // malformed fragment → {}

 /** Merge two object types, preferring properties from `B` when keys overlap. */
type Merge<A, B> = {
  [K in keyof A | keyof B]: K extends keyof B ? B[K] : A[K];
};

export class EventEmitter<TEvents extends Record<string, unknown[]>> {
  // Store handlers per event name; each entry is an ordered array of callbacks.
  private readonly handlers: {
    [K in keyof TEvents]?: Array<(...args: TEvents[K]) => void>;
  } = {};

  /**
   * Register a handler for the given event.
   *
   * @param name    Event name – must be a key of `TEvents`.
   * @param handler Callback whose parameters are inferred from the event's tuple type.
   */
  on<K extends keyof TEvents>(name: K, handler: (...args: TEvents[K]) => void): void {
    const list = this.handlers[name] as Array<(...args: TEvents[K]) => void> | undefined;
    if (list) {
      list.push(handler);
    } else {
      this.handlers[name] = [handler];
    }
  }

  /**
   * Emit an event, invoking all registered handlers in registration order.
   *
   * @param name Event name – must be a key of `TEvents`.
   * @param args Arguments matching the tuple type associated with the event.
   */
  emit<K extends keyof TEvents>(name: K, ...args: TEvents[K]): void {
    const list = this.handlers[name] as Array<(...args: TEvents[K]) => void> | undefined;
    if (list) {
      for (const handler of list) {
        handler(...args);
      }
    }
  }
}

