/**
 * A binary heap implementation with a custom comparator.
 * The heap stores numbers only (no `any` usage) and provides
 * O(log n) push / pop operations.
 */
class Heap {
    private data: number[] = [];
    /** comparator(a,b) === true  ⇔ a has higher priority than b */
    private readonly cmp: (a: number, b: number) => boolean;

    constructor(comparator: (a: number, b: number) => boolean) {
        this.cmp = comparator;
    }

    /** Number of elements in the heap */
    size(): number {
        return this.data.length;
    }

    /** Element with highest priority (root) */
    peek(): number {
        if (!this.data.length) throw new Error('Heap is empty');
        return this.data[0];
    }

    /** Insert a value */
    push(value: number): void {
        this.data.push(value);
        this.bubbleUp(this.data.length - 1);
    }

    /** Remove and return the root element */
    pop(): number {
        if (!this.data.length) throw new Error('Heap is empty');
        const top = this.data[0];
        const last = this.data.pop()!;
        if (this.data.length) {
            this.data[0] = last;
            this.bubbleDown(0);
        }
        return top;
    }

    private parent(idx: number): number {
        return (idx - 1) >> 1;
    }
    private left(idx: number): number {
        return idx * 2 + 1;
    }
    private right(idx: number): number {
        return idx * 2 + 2;
    }

    private bubbleUp(idx: number): void {
        while (idx > 0) {
            const p = this.parent(idx);
            if (!this.cmp(this.data[idx], this.data[p])) break;
            [this.data[idx], this.data[p]] = [this.data[p], this.data[idx]];
            idx = p;
        }
    }

    private bubbleDown(idx: number): void {
        const n = this.data.length;
        while (true) {
            let best = idx;
            const l = this.left(idx);
            const r = this.right(idx);

            if (l < n && this.cmp(this.data[l], this.data[best])) best = l;
            if (r < n && this.cmp(this.data[r], this.data[best])) best = r;

            if (best === idx) break;
            [this.data[idx], this.data[best]] = [this.data[best], this.data[idx]];
            idx = best;
        }
    }
}

/**
 * MedianStream maintains a running median of an incoming numeric stream.
 *
 * API:
 *   add(n: number): void      – insert a new value
 *   median(): number          – current median (average of two middle values when even)
 *
 * Throws if `median()` is called before any value has been added.
 */
export class MedianStream {
    // Max‑heap for the lower half (largest element on top)
    private readonly low = new Heap((a, b) => a > b);
    // Min‑heap for the upper half (smallest element on top)
    private readonly high = new Heap((a, b) => a < b);

    /** Insert a number into the stream */
    add(n: number): void {
        // Decide which heap receives the new element
        if (this.low.size() === 0 || n <= this.low.peek()) {
            this.low.push(n);
        } else {
            this.high.push(n);
        }

        // Re‑balance so that sizes differ by at most 1
        if (this.low.size() > this.high.size() + 1) {
            this.high.push(this.low.pop());
        } else if (this.high.size() > this.low.size() + 1) {
            this.low.push(this.high.pop());
        }
    }

    /** Return the current median */
    median(): number {
        const total = this.low.size() + this.high.size();
        if (total === 0) {
            throw new Error('Median requested before any numbers were added');
        }

        if (this.low.size() > this.high.size()) {
            return this.low.peek();
        }
        if (this.high.size() > this.low.size()) {
            return this.high.peek();
        }
        // Even count – average the two middle values
        return (this.low.peek() + this.high.peek()) / 2;
    }
}
